UPDATE STOCPODT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , INV_QT      = (INV_QT, 0) + (#{INV_QT}, 0) - (#{OLD_INV_QT}, 0)
    , PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND PO_NUM   = #{PO_NUM}
  AND PO_SQ    = #{PO_SQ}

UPDATE STOCPRDT SET
      MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PROGRESS_CD = CASE WHEN #{TYPE} = 'SEND' THEN #{PROGRESS_CD} ELSE PROGRESS_CD END
WHERE GATE_CD  = #{ses.gateCd}
  AND (BUYER_CD, PR_NUM, PR_SQ) IN (
  			SELECT PB_BUYER_CD, PR_NUM, PR_SQ
  			  FROM STOCPODT
  			 WHERE GATE_CD  = #{ses.gateCd}
  			   AND BUYER_CD = #{BUYER_CD}
  			   AND PO_NUM   = #{PO_NUM}
  			   AND PO_SQ    = #{PO_SQ}
  	  )
  AND DEL_FLAG = '0'

