UPDATE STOCIVHD SET
      INV_AMT      = (INV_AMT, 0) + (#{INV_AMT}, 0) - (#{OLD_INV_AMT}, 0)
    , VAT_AMT      = (VAT_AMT, 0) + (#{VAT_AMT}, 0) - (#{OLD_VAT_AMT}, 0)
    , SUPPLY_AMT   = (SUPPLY_AMT, 0) + ((#{INV_AMT}, 0) - (#{VAT_AMT}, 0)) - ((#{OLD_INV_AMT}, 0) - (#{OLD_VAT_AMT}, 0))
    , PROGRESS_CD  = #{PROGRESS_CD}
    , GUAR_TYPE    = #{GUAR_TYPE}
    , GUAR_PERCENT = #{GUAR_PERCENT}
    , GUAR_QT      = (#{GUAR_QT}, 0)
    , VAT_FLAG     = #{VAT_TYPE}
    , GUAR_AMT     = (#{GUAR_AMT}, 0)
    , GUAR_TYPE2   = #{GUAR_TYPE2}
    , GUARANTEER   = #{GUARANTEER}
    , ATT_FILE_NUM = #{GUAR_ATT_FILE_NUM}
    , RMK          = #{RMK}
    , INSU_STATUS  = #{INSU_STATUS}
    , MOD_DATE     = SYSDATE
    , MOD_USER_ID  = #{ses.userId}
WHERE GATE_CD  = #{ses.gateCd}
  AND BUYER_CD = #{BUYER_CD}
  AND INV_NUM  = #{INV_NUM}

