INSERT INTO STOCIVGH (
    GATE_CD
    , BUYER_CD
    , INV_NUM
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , REQ_CNT
    , SUBJECT
    , ATT_FILE_NUM
    , SEND_DATE
    , PO_NUM
    , PAY_CNT
    , PURCHASE_TYPE
    , VENDOR_CD
    , VENDOR_USER_NM
    , VENDOR_TEL_NUM
    , VENDOR_CELL_NUM
    , RMK_TEXT_NUM
    , INV_SEND_DATE
)
VALUES (
    #{ses.gateCd}
    , #{BUYER_CD}
    , #{INV_NUM}
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    ,(SELECT (MAX(REQ_CNT), 0) + 1
        FROM STOCIVGH
       WHERE GATE_CD  = #{ses.gateCd}
         AND BUYER_CD = #{BUYER_CD}
         AND PO_NUM   = #{PO_NUM}
         AND DEL_FLAG = '0')
    , #{SUBJECT}
    , #{ATT_FILE_NUM}
    , #{SEND_DATE}
    , #{PO_NUM}
    , #{PAY_CNT}
    , #{PURCHASE_TYPE}
    , #{ses.companyCd}
    , #{PIC_USER_NM}
    , #{PIC_TEL_NUM}
    , #{PIC_CELL_NUM}
    , #{RMK_TEXT_NUM}
    ,(CASE WHEN #{TYPE} = 'SEND' THEN SYSDATE ELSE NULL END)
)

